'use client';

import React, { useEffect, useState } from 'react';
import { useRouter } from 'next/navigation';
import { dashboardApi, MaintenanceAlertsResponse, MaintenanceAlert } from '@/lib/api';

// Maintenance type colors
const typeColors: Record<string, string> = {
  PM1: 'bg-blue-100 text-blue-800',
  PM2: 'bg-indigo-100 text-indigo-800',
  HM: 'bg-purple-100 text-purple-800',
  OVH: 'bg-orange-100 text-orange-800',
};

// Maintenance type descriptions
const typeDescriptions: Record<string, string> = {
  PM1: 'Preventive Maintenance Level 1',
  PM2: 'Preventive Maintenance Level 2',
  HM: 'Heavy Maintenance',
  OVH: 'Overhaul',
};

interface AlertItemProps {
  alert: MaintenanceAlert;
  onClick?: () => void;
}

/**
 * Individual Alert Item
 */
function AlertItem({ alert, onClick }: AlertItemProps) {
  const formatDate = (dateStr: string) => {
    const date = new Date(dateStr);
    return date.toLocaleDateString('en-GB', {
      day: '2-digit',
      month: 'short',
    });
  };

  return (
    <div
      className="flex items-center justify-between py-3 px-4 hover:bg-gray-50 cursor-pointer transition-colors border-b border-gray-100 last:border-b-0"
      onClick={onClick}
      role="button"
      tabIndex={0}
    >
      <div className="flex items-center space-x-3">
        <span
          className={`px-2 py-1 text-xs font-medium rounded ${typeColors[alert.type] || 'bg-gray-100 text-gray-800'}`}
          title={typeDescriptions[alert.type]}
        >
          {alert.type}
        </span>
        <div>
          <div className="font-medium text-gray-900">{alert.trainId}</div>
          <div className="text-sm text-gray-500">
            {alert.depot} ({alert.depotCode})
          </div>
        </div>
      </div>
      <div className="text-right">
        <div className="text-sm font-medium text-gray-900">
          {formatDate(alert.date)}
        </div>
        <div className="text-xs text-gray-500">
          {alert.durationDays} {alert.durationDays === 1 ? 'day' : 'days'}
        </div>
      </div>
    </div>
  );
}

/**
 * Maintenance Alerts Component
 *
 * Displays upcoming maintenance events in the next 7 days
 * with counts by type and a list of upcoming events.
 */
export function MaintenanceAlerts() {
  const router = useRouter();
  const [data, setData] = useState<MaintenanceAlertsResponse | null>(null);
  const [loading, setLoading] = useState(true);
  const [error, setError] = useState<string | null>(null);

  useEffect(() => {
    async function fetchAlerts() {
      setLoading(true);
      const { data, error } = await dashboardApi.getMaintenanceAlerts();

      if (error) {
        setError(error);
      } else if (data) {
        setData(data);
      }
      setLoading(false);
    }

    fetchAlerts();
  }, []);

  const handleAlertClick = (_alertId: string) => {
    router.push('/maintenance');
  };

  const handleViewAll = () => {
    router.push('/maintenance');
  };

  if (loading) {
    return (
      <div className="bg-white shadow rounded-lg overflow-hidden animate-pulse">
        <div className="p-4 border-b border-gray-100">
          <div className="h-5 bg-gray-200 rounded w-1/3 mb-2"></div>
          <div className="flex space-x-2">
            {[...Array(4)].map((_, i) => (
              <div key={i} className="h-6 bg-gray-200 rounded w-12"></div>
            ))}
          </div>
        </div>
        {[...Array(3)].map((_, i) => (
          <div key={i} className="p-4 border-b border-gray-100">
            <div className="h-4 bg-gray-200 rounded w-2/3 mb-2"></div>
            <div className="h-3 bg-gray-200 rounded w-1/2"></div>
          </div>
        ))}
      </div>
    );
  }

  if (error) {
    return (
      <div className="bg-red-50 border border-red-200 rounded-lg p-4">
        <p className="text-red-800">
          <strong>Error loading maintenance alerts:</strong> {error}
        </p>
      </div>
    );
  }

  if (!data || data.totalUpcoming === 0) {
    return (
      <div className="bg-green-50 border border-green-200 rounded-lg p-6">
        <div className="flex items-center">
          <svg className="w-5 h-5 text-green-500 mr-2" fill="none" stroke="currentColor" viewBox="0 0 24 24">
            <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M5 13l4 4L19 7" />
          </svg>
          <span className="text-green-800 font-medium">
            No scheduled maintenance in the next 7 days
          </span>
        </div>
      </div>
    );
  }

  return (
    <div className="bg-white shadow rounded-lg overflow-hidden">
      {/* Summary Header */}
      <div className="p-4 border-b border-gray-200 bg-gray-50">
        <div className="flex items-center justify-between mb-3">
          <h3 className="font-semibold text-gray-900">
            Upcoming Maintenance
          </h3>
          <span className="text-sm text-gray-600">
            {data.totalUpcoming} event{data.totalUpcoming !== 1 ? 's' : ''} in next 7 days
          </span>
        </div>

        {/* Type Counts */}
        <div className="flex flex-wrap gap-2">
          {Object.entries(data.countByType).map(([type, count]) => (
            count > 0 && (
              <span
                key={type}
                className={`px-2 py-1 text-xs font-medium rounded ${typeColors[type]}`}
                title={typeDescriptions[type]}
              >
                {type}: {count}
              </span>
            )
          ))}
        </div>
      </div>

      {/* Alerts List */}
      <div>
        {data.alerts.map((alert) => (
          <AlertItem
            key={alert.id}
            alert={alert}
            onClick={() => handleAlertClick(alert.id)}
          />
        ))}
      </div>

      {/* View All Link */}
      {data.totalUpcoming > 5 && (
        <div className="p-3 bg-gray-50 text-center">
          <button
            className="text-sm text-primary-600 hover:text-primary-800 font-medium"
            onClick={handleViewAll}
          >
            View all {data.totalUpcoming} maintenance events вҶ’
          </button>
        </div>
      )}
    </div>
  );
}
